mapper.select:
SELECT 
FROM task_warning
WHERE user_id = #{userId}
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

mapper.update:
UPDATE task_warning
SET is_read = 1
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM task_warning
WHERE user_id = #{userId}
  AND proc_inst_id = #{procInstId}
  AND node_key = #{nodeKey}
  AND warn_type = #{warnType}

mapper.update:
UPDATE task_warning
SET is_read = 1, resolved = 1
WHERE proc_inst_id = #{procInstId}
  AND node_key = #{nodeKey}
  AND (is_read = 0 OR resolved = 0)
